    void visit(AstClassExtends* nodep) override {
        // Resolve the symbol and get the class.
        // If it is a parameterized case, the class will be resolved after V3Param.cpp
        if (nodep->user3SetOnce()) return;
        // If the class is resolved, there is nothing more to do
        if (nodep->classOrNullp()) return;
        LINKDOT_VISIT_START();
        if (m_statep->forPrimary()) {
            if (nodep->childDTypep()) return;
            AstNode* cprp = nodep->classOrPkgsp();
            VSymEnt* lookSymp = m_curSymp;
            if (AstDot* const dotp = VN_CAST(cprp, Dot)) {
                dotp->user3(true);
                if (AstClassOrPackageRef* lookNodep = VN_CAST(dotp->lhsp(), ClassOrPackageRef)) {
                    iterate(lookNodep);
                    cprp = dotp->rhsp();
                    VSymEnt* const foundp = m_statep->resolveClassOrPackage(
                        lookSymp, lookNodep, true, false, nodep->verilogKwd());
                    if (!foundp) return;
                    UASSERT_OBJ(lookNodep->classOrPackageSkipp(), nodep, "Bad package link");
                    lookSymp = m_statep->getNodeSym(lookNodep->classOrPackageSkipp());
                } else {
                    dotp->lhsp()->v3error("Attempting to extend"  // LCOV_EXCL_LINE
                                          " using non-class under dot");
                }
            }
            AstClassOrPackageRef* const cpackagerefp = VN_CAST(cprp, ClassOrPackageRef);
            if (VL_UNCOVERABLE(!cpackagerefp)) {
                // Linking the extend gives an error before this is hit
                nodep->v3error("Attempting to extend using non-class");  // LCOV_EXCL_LINE
                return;
            }
            VSymEnt* const foundp = m_statep->resolveClassOrPackage(lookSymp, cpackagerefp, true,
                                                                    true, nodep->verilogKwd());
            if (foundp) {
                if (AstClass* const classp = VN_CAST(foundp->nodep(), Class)) {
                    AstPin* paramsp = cpackagerefp->paramsp();
                    if (paramsp) {
                        paramsp = paramsp->cloneTree(true);
                        nodep->parameterized(true);
                    }
                    nodep->childDTypep(new AstClassRefDType{nodep->fileline(), classp, paramsp});
                    // Link pins
                    iterate(nodep->childDTypep());
                } else if (AstParamTypeDType* const paramp
                           = VN_CAST(foundp->nodep(), ParamTypeDType)) {
                    AstRefDType* const refParamp
                        = new AstRefDType{nodep->fileline(), paramp->name()};
                    refParamp->refDTypep(paramp);
                    nodep->childDTypep(refParamp);
                    nodep->parameterized(true);
                } else {
                    nodep->v3warn(E_UNSUPPORTED,
                                  "Unsupported: " << foundp->nodep()->prettyTypeName()
                                                  << " in 'class extends'");
                    return;
                }
            } else {
                return;
            }
            if (!nodep->childDTypep()) nodep->v3error("Attempting to extend using non-class");
            nodep->classOrPkgsp()->unlinkFrBack()->deleteTree();
        } else {
            // Probably a parameter
            if (AstRefDType* const refp = VN_CAST(nodep->childDTypep(), RefDType)) {
                if (AstClassRefDType* classRefp = VN_CAST(refp->skipRefp(), ClassRefDType)) {
                    // Resolved to a class reference.
                    refp->replaceWith(classRefp->cloneTree(false));
                    VL_DO_DANGLING(pushDeletep(refp), refp);
                } else {
                    // Unable to resolve the ref type to a class reference.
                    // Get the value of type parameter passed to the class instance,
                    // to print the helpful error message.
                    const AstNodeDType* typep = refp->refDTypep();
                    while (true) {
                        if (const AstParamTypeDType* const atypep
                            = VN_CAST(typep, ParamTypeDType)) {
                            typep = atypep->subDTypep();
                            continue;
                        }
                        if (const AstRequireDType* const atypep = VN_CAST(typep, RequireDType)) {
                            typep = atypep->subDTypep();
                            continue;
                        }
                        break;
                    }
                    typep->v3error("Attempting to extend using non-class");
                }
            }
        }
    }
    void visit(AstClass* nodep) override {
        if (nodep->user3SetOnce()) return;
        LINKDOT_VISIT_START();
        UINFO(5, indent() << "visit " << nodep);
        checkNoDot(nodep);
        VL_RESTORER(m_curSymp);
        VL_RESTORER(m_modSymp);
        VL_RESTORER(m_modp);
        VL_RESTORER(m_ifClassImpNames);
        VL_RESTORER(m_insideClassExtParam);
        {
            m_ds.init(m_curSymp);
            // Until overridden by a SCOPE
            m_ds.m_dotSymp = m_curSymp = m_modSymp = m_statep->getNodeSym(nodep);
            m_modp = nodep;
            int next = 0;
            for (AstClassExtends* cextp = nodep->extendsp(); cextp;
                 cextp = VN_AS(cextp->nextp(), ClassExtends)) {
                // Replace abstract reference with hard pointer
                // Will need later resolution when deal with parameters
                if (++next == 2 && !nodep->isInterfaceClass() && !cextp->isImplements()) {
                    cextp->v3error("Multiple inheritance illegal on non-interface classes"
                                   " (IEEE 1800-2023 8.13)");
                }
                iterate(cextp);
                if (m_statep->forPrimary()) {
                    if (cextp->parameterized()) {
                        // Parameters in extends statement.
                        // The class can't be resolved in the current pass.
                        m_extendsParam.insert(nodep);
                        m_insideClassExtParam = true;
                    }
                    if (AstClassRefDType* const classRefp
                        = VN_CAST(cextp->childDTypep(), ClassRefDType)) {
                        AstClass* const classp = classRefp->classp();
                        if (classp != nodep) iterate(classp);
                        if (m_extendsParam.find(classp) != m_extendsParam.end()) {
                            // One of its super classes has parameters in extends statement.
                            // Some links may not be resolved in the first pass.
                            m_extendsParam.insert(nodep);
                            m_insideClassExtParam = true;
                        }
                        // Issue #6814: When extends is parameterized, type parameters from
                        // the parent class (like REQ/RSP in uvm_driver) need to be available
                        // in the derived class. We build a map of parameter bindings from
                        // the PINs, then iterate through all parent's type parameters.
                        if (cextp->parameterized() && !cextp->isImplements()) {
                            VSymEnt* const parentSymp = m_statep->getNodeSym(classp);
                            UINFO(5, "Issue #6814: Processing parameterized extends "
                                      << classp->name());

                            // Build a map of pin number -> bound type from the PINs
                            std::map<int, AstNode*> pinBindings;
                            std::map<string, AstNode*> namedBindings;
                            for (AstPin* pinp = classRefp->paramsp(); pinp;
                                 pinp = VN_AS(pinp->nextp(), Pin)) {
                                if (pinp->exprp()) {
                                    if (!pinp->name().empty() && pinp->name()[0] != '_') {
                                        namedBindings[pinp->name()] = pinp->exprp();
                                    }
                                    pinBindings[pinp->pinNum()] = pinp->exprp();
                                }
                            }

                            // Iterate through all ParamTypeDType in parent class
                            for (AstNode* stmtp = classp->stmtsp(); stmtp;
                                 stmtp = stmtp->nextp()) {
                                AstParamTypeDType* const ptp = VN_CAST(stmtp, ParamTypeDType);
                                if (!ptp) continue;

                                AstNode* boundTypep = nullptr;

                                // Check for named binding first
                                auto namedIt = namedBindings.find(ptp->name());
                                if (namedIt != namedBindings.end()) {
                                    boundTypep = namedIt->second;
                                } else {
                                    // Check for positional binding
                                    // Find param number from symbol table
                                    for (auto it = pinBindings.begin();
                                         it != pinBindings.end(); ++it) {
                                        const string numName
                                            = "__paramNumber" + cvtToStr(it->first);
                                        const VSymEnt* const symEntryp
                                            = parentSymp->findIdFlat(numName);
                                        if (symEntryp && symEntryp->nodep() == ptp) {
                                            boundTypep = it->second;
                                            break;
                                        }
                                    }
                                }

                                // If no explicit binding, check if default is a reference to
                                // another type parameter that we already bound
                                if (!boundTypep && ptp->subDTypep()) {
                                    // The default may be wrapped in RequireDType
                                    AstNodeDType* defaultDtp = ptp->subDTypep();
                                    if (AstRequireDType* const reqp
                                        = VN_CAST(defaultDtp, RequireDType)) {
                                        defaultDtp = reqp->subDTypep();
                                    }
                                    if (defaultDtp) {
                                        if (AstRefDType* const refp
                                            = VN_CAST(defaultDtp, RefDType)) {
                                            if (AstParamTypeDType* const refPtp = VN_CAST(
                                                    refp->refDTypep(), ParamTypeDType)) {
                                                // Default references another type param
                                                // Look up what that param is bound to
                                                auto refIt = namedBindings.find(refPtp->name());
                                                if (refIt != namedBindings.end()) {
                                                    boundTypep = refIt->second;
                                                    UINFO(5, "Issue #6814: " << ptp->name()
                                                              << " defaults to " << refPtp->name()
                                                              << " -> " << boundTypep);
                                                }
                                            }
                                        }
                                    }
                                }

                                if (boundTypep) {
                                    // Only insert if the name doesn't already exist in derived
                                    // class. This handles the case where derived class has its
                                    // own type parameter with the same name that shadows the
                                    // parent's (e.g., "class D #(type T) extends B #(T)")
                                    if (!m_curSymp->findIdFlat(ptp->name())) {
                                        UINFO(5, "Issue #6814: Insert " << ptp->name() << " -> "
                                                  << boundTypep << " into " << m_curSymp->nodep());
                                        m_statep->insertSym(m_curSymp, ptp->name(), boundTypep,
                                                            nullptr);
                                    } else {
                                        UINFO(5, "Issue #6814: Skip " << ptp->name()
                                                  << " (already exists in derived class)");
                                    }
                                    // Also add to namedBindings so chained defaults work
                                    namedBindings[ptp->name()] = boundTypep;
                                }
                            }
                        }
                    }
                }

                if (AstClass* const baseClassp = cextp->classOrNullp()) {
                    // Already converted. Update symbol table to link unlinked members.
                    // Base class has to be visited in a case if its extends statement
                    // needs to be handled. Recursive inheritance was already checked.
                    // Must be here instead of in LinkDotParam to handle
                    // "class (type T) extends T".
                    if (baseClassp == nodep) {
                        cextp->v3error("Attempting to extend class " << nodep->prettyNameQ()
                                                                     << " from itself");
                    } else if (cextp->isImplements() && !baseClassp->isInterfaceClass()) {
                        cextp->v3error("Attempting to implement from non-interface class "
                                       << baseClassp->prettyNameQ() << '\n'
                                       << "... Suggest use 'extends'");
                    } else if (!cextp->isImplements() && !nodep->isInterfaceClass()
                               && baseClassp->isInterfaceClass()) {
                        cextp->v3error("Attempting to extend from interface class "
                                       << baseClassp->prettyNameQ() << '\n'
                                       << "... Suggest use 'implements'");
                    }
                    baseClassp->isExtended(true);
                    nodep->isExtended(true);
                    iterate(baseClassp);
                    importSymbolsFromExtended(nodep, cextp);
                    continue;
                }
            }
            m_ds.m_dotSymp = m_curSymp;

            iterateChildren(nodep);
        }
        // V3Width when determines types needs to find enum values and such
        // so add members pointing to appropriate enum values
        {
            VMemberMap memberMap;
            for (VSymEnt::const_iterator it = m_curSymp->begin(); it != m_curSymp->end(); ++it) {
                AstNode* const itemp = it->second->nodep();
                if (!memberMap.findMember(nodep, it->first)) {
                    if (AstEnumItem* const aitemp = VN_CAST(itemp, EnumItem)) {
                        AstEnumItemRef* const newp = new AstEnumItemRef{
                            aitemp->fileline(), aitemp, it->second->classOrPackagep()};
                        UINFO(8, indent()
                                     << "Class import noderef '" << it->first << "' " << newp);
                        nodep->addMembersp(newp);
                        memberMap.insert(nodep, newp);
                    }
                }
            }
        }
        m_ds.m_dotSymp = VL_RESTORER_PREV(m_curSymp);
    }
    void visit(AstRefDType* nodep) override {

        if (auto* const typeOfp = nodep->typeofp()) {
            iterate(typeOfp);
            // After iteration, typeofp() may have been replaced with a resolved type
            // (e.g., DOT expression like if0.rq_t resolved to REFDTYPE)
            // If it's now a NodeDType, replace this RefDType with it
            if (AstNodeDType* const resolvedDTypep = VN_CAST(nodep->typeofp(), NodeDType)) {
                UINFO(9,
                      indent() << "iface capture typeofp resolved to dtype, replacing RefDType\n");
                resolvedDTypep->unlinkFrBack();
                nodep->replaceWith(resolvedDTypep);
                VL_DO_DANGLING(pushDeletep(nodep), nodep);
                // If the resolved dtype is a RefDType with an interface typedef,
                // ensure it's captured for re-resolution during paramed pass
                if (AstRefDType* const resolvedRefp = VN_CAST(resolvedDTypep, RefDType)) {
                    if (resolvedRefp->user2p() && !V3LinkDotIfaceCapture::find(resolvedRefp)) {
                        AstCell* const cellp = VN_AS(resolvedRefp->user2p(), Cell);
                        UINFO(9, indent() << "iface capture re-capture resolved RefDType="
                                          << resolvedRefp << " cell=" << cellp << "\n");
                        V3LinkDotIfaceCapture::add(resolvedRefp, cellp, m_modp,
                                                   resolvedRefp->typedefp());
                    }
                }
            }
            return;
        }

        // Resolve its reference
        if (V3LinkDotIfaceCapture::find(nodep)) {
            UINFO(9, indent() << "iface capture visit captured typedef ptr=" << nodep
                              << " user2=" << nodep->user2p());
        }
        if (m_statep->forParamed() && nodep->user3()) {
            if (V3LinkDotIfaceCapture::enabled() && nodep->user2p()) {
                UINFO(9, indent() << "iface capture clear user3 for captured typedef name="
                                  << nodep->name() << " cell=" << nodep->user2p());
            }
            nodep->user3(false);
        }
        if (nodep->user3SetOnce()) {
            if (V3LinkDotIfaceCapture::enabled() && nodep->user2p()) {
                UINFO(9, indent() << "iface capture skip revisit name=" << nodep->name()
                                  << " already user3 and captured cell=" << nodep->user2p());
            }
            return;
        }
        LINKDOT_VISIT_START();
        UINFO(5, indent() << "visit " << nodep);
        if (AstNode* const cpackagep = nodep->classOrPackageOpp()) {
            if (AstClassOrPackageRef* const cpackagerefp = VN_CAST(cpackagep, ClassOrPackageRef)) {
                iterate(cpackagerefp);
                const AstClass* const clsp = VN_CAST(cpackagerefp->classOrPackageNodep(), Class);
                if (clsp && clsp->hasGParam()) {
                    // Unable to link before the instantiation of parameter classes.
                    // The class reference node still has to be visited now to later link
                    // parameters.
                    iterate(cpackagep);
                    return;
                }
                if (!cpackagerefp->classOrPackageSkipp()) {
                    VSymEnt* const foundp = m_statep->resolveClassOrPackage(
                        m_ds.m_dotSymp, cpackagerefp, true, false, "class/package reference");
                    if (!foundp) return;
                }
                nodep->classOrPackagep(cpackagerefp->classOrPackageSkipp());
                if (!VN_IS(nodep->classOrPackagep(), Class)
                    && !VN_IS(nodep->classOrPackagep(), Package)) {
                    if (m_statep->forPrimary()) {
                        // It may be a type that comes from parameter class that is not
                        // instantioned yet
                        iterate(cpackagep);
                        return;
                    }
                    // Likely impossible, as error thrown earlier
                    cpackagerefp->v3error(  // LCOV_EXCL_LINE
                        "'::' expected to reference a class/package but referenced '"
                        << (nodep->classOrPackagep() ? nodep->classOrPackagep()->prettyTypeName()
                                                     : "<unresolved-object>")
                        << "'\n"
                        << cpackagerefp->warnMore() + "... Suggest '.' instead of '::'");
                }
            } else {
                cpackagep->v3warn(E_UNSUPPORTED,
                                  "Unsupported: Multiple '::' package/class reference");
            }
            VL_DO_DANGLING(pushDeletep(cpackagep->unlinkFrBack()), cpackagep);
        }

        const bool capEnable = V3LinkDotIfaceCapture::enabled();
        const auto* const capEntryp = capEnable ? V3LinkDotIfaceCapture::find(nodep) : nullptr;
        const bool captureMapHit = capEntryp != nullptr;
        AstCell* const captureEntryCellp = capEntryp ? capEntryp->cellp : nullptr;
        AstTypedef* const capturedTypedefp = capEntryp ? capEntryp->typedefp : nullptr;
        const VSymEnt* const capturedTypedefSymp
            = capturedTypedefp ? m_statep->getNodeSym(capturedTypedefp) : nullptr;

        const bool ifaceCaptured = capEnable && nodep->user2p();
        const bool missingIfaceContext = captureMapHit && !ifaceCaptured;
        const char* const passLabel = m_statep->forParamed() ? "paramed" : "primary";
        if (missingIfaceContext) {
            UINFO(9, indent() << "iface capture captured typedef missing user2 name="
                              << nodep->name() << " ref=" << nodep << " pass=" << passLabel
                              << " entryCell=" << captureEntryCellp);
        }
        AstCell* const capturedCellp = ifaceCaptured ? VN_CAST(nodep->user2p(), Cell) : nullptr;

        bool forcedIfaceDotScope = false;
        bool resolvedCapturedTypedef = false;
        bool captureEntryRetired = false;
        const auto retireCapture = [&](const char* reason) {
            if (!ifaceCaptured || captureEntryRetired) return;
            const auto* entry = V3LinkDotIfaceCapture::find(nodep);
            AstCell* const entryCell = entry ? entry->cellp : nullptr;
            UINFO(9, indent() << "iface capture retire captured typedef reason=" << reason
                              << " name=" << nodep->name() << " pass=" << passLabel
                              << " user2=" << nodep->user2p() << " entryCell=" << entryCell);
            const bool erased = V3LinkDotIfaceCapture::erase(nodep);
            captureEntryRetired = true;
            UINFO(9, indent() << "iface capture retire erase result name=" << nodep->name()
                              << " erased=" << erased);
        };
        if (ifaceCaptured && m_statep->forParamed()) {
            UINFO(9, indent() << "iface capture captured typedef name=" << nodep->name()
                              << " typedef=" << nodep->typedefp() << " cell=" << capturedCellp);
            if (nodep->typedefp()) {
                UINFO(9, indent() << "iface capture refresh typedef binding name=" << nodep->name()
                                  << " typedef=" << nodep->typedefp()
                                  << " cell=" << capturedCellp);
                nodep->typedefp(nullptr);
                nodep->classOrPackagep(nullptr);
            }
        }
        if (m_ds.m_dotp && (m_ds.m_dotPos == DP_PACKAGE || m_ds.m_dotPos == DP_SCOPE)) {
            UASSERT_OBJ(VN_IS(m_ds.m_dotp->lhsp(), ClassOrPackageRef), m_ds.m_dotp->lhsp(),
                        "Bad package link");
            auto* const cpackagerefp = VN_CAST(m_ds.m_dotp->lhsp(), ClassOrPackageRef);
            UASSERT_OBJ(cpackagerefp->classOrPackageSkipp(), m_ds.m_dotp->lhsp(),
                        "Bad package link");
            nodep->classOrPackagep(cpackagerefp->classOrPackageSkipp());
            m_ds.m_dotPos = DP_SCOPE;
        } else if (!ifaceCaptured) {
            checkNoDot(nodep);
        } else {
            UINFO(9, indent() << "iface capture consume captured iface context name="
                              << nodep->name() << " cell=" << capturedCellp);
            m_ds.m_dotPos = DP_SCOPE;
            forcedIfaceDotScope = true;
            // Set dotSymp to the cell's symbol entry so lookup happens in the interface scope
            if (capturedCellp && m_statep->existsNodeSym(capturedCellp)) {
                VSymEnt* const cellSymp = m_statep->getNodeSym(capturedCellp);
                m_ds.m_dotSymp = cellSymp;
                UINFO(9, indent() << "iface capture set dotSymp to cell scope cellSymp="
                                  << cellSymp << " node=" << cellSymp->nodep());
            }
        }
        if (!nodep->typedefp() && !nodep->subDTypep()) {
            if (ifaceCaptured) {
                UINFO(9, indent() << "iface capture lookup start name=" << nodep->name()
                                  << " dotPos=" << static_cast<int>(m_ds.m_dotPos) << " dotSym="
                                  << m_ds.m_dotSymp << " classPkg=" << nodep->classOrPackagep());
            }
            const VSymEnt* foundp;
            if (nodep->classOrPackagep()) {
                foundp = m_statep->getNodeSym(nodep->classOrPackagep())->findIdFlat(nodep->name());
            } else if (m_ds.m_dotPos == DP_FIRST || m_ds.m_dotPos == DP_NONE) {
                foundp = m_curSymp->findIdFallback(nodep->name());
            } else {
                // Use dotSymp if set (e.g., for captured interface typedefs), else curSymp
                VSymEnt* const lookupSymp = m_ds.m_dotSymp ? m_ds.m_dotSymp : m_curSymp;
                foundp = lookupSymp->findIdFlat(nodep->name());
            }
            if (ifaceCaptured && capturedTypedefp) {
                // When we have a captured interface typedef context, use the captured typedef
                // instead of any local lookup result. This handles the case where the local
                // typedef has the same name as the interface typedef (e.g., `typedef if0.rq_t
                // rq_t;`)
                UINFO(9, indent() << "iface capture binding via captured typedef fallback name="
                                  << nodep->name() << " typedef=" << capturedTypedefp);
                nodep->typedefp(capturedTypedefp);
                nodep->classOrPackagep(capturedTypedefSymp ? capturedTypedefSymp->classOrPackagep()
                                                           : nullptr);
                resolvedCapturedTypedef = true;
            }
            if (!resolvedCapturedTypedef && foundp) {
                VSymEnt* const parentSymp = foundp->parentp();
                UINFO(9, indent() << "iface capture resolved typedef name=" << nodep->name()
                                  << " foundNode=" << foundp->nodep() << " parentNode="
                                  << (parentSymp ? parentSymp->nodep() : nullptr));
            }
            if (!resolvedCapturedTypedef) {
                if (AstTypedef* const defp
                    = foundp ? VN_CAST(foundp->nodep(), Typedef) : nullptr) {
                    // Don't check if typedef is to a <type T>::<reference> as might not be
                    // resolved yet
                    if (!nodep->classOrPackagep() && !defp->isUnderClass())
                        checkDeclOrder(nodep, defp);
                    nodep->typedefp(defp);
                    nodep->classOrPackagep(foundp->classOrPackagep());
                    resolvedCapturedTypedef = true;
                } else if (AstParamTypeDType* const defp
                           = foundp ? VN_CAST(foundp->nodep(), ParamTypeDType) : nullptr) {
                    if (defp == nodep->backp()) {  // Where backp is typically typedef
                        nodep->v3error("Reference to '"
                                       << m_ds.m_dotText << (m_ds.m_dotText == "" ? "" : ".")
                                       << nodep->prettyName() << "'"
                                       << " type would form a recursive definition");
                        nodep->refDTypep(nodep->findVoidDType());  // Try to reduce later errors
                    } else {
                        nodep->refDTypep(defp);
                        nodep->classOrPackagep(foundp->classOrPackagep());
                        resolvedCapturedTypedef = true;
                    }
                } else if (AstClass* const defp
                           = foundp ? VN_CAST(foundp->nodep(), Class) : nullptr) {
                    // Don't check if typedef is to a <type T>::<reference> as might not be
                    // resolved yet
                    if (!nodep->classOrPackagep()) checkDeclOrder(nodep, defp);
                    AstPin* const paramsp = nodep->paramsp();
                    if (paramsp) paramsp->unlinkFrBackWithNext();
                    AstClassRefDType* const newp
                        = new AstClassRefDType{nodep->fileline(), defp, paramsp};
                    newp->classOrPackagep(foundp->classOrPackagep());
                    resolvedCapturedTypedef = true;
                    retireCapture("resolved");  // Must retire before replacing node
                    nodep->replaceWith(newp);
                    VL_DO_DANGLING(pushDeletep(nodep), nodep);
                    return;
                } else if (m_insideClassExtParam) {
                    return;
                } else {
                    if (foundp) {
                        UINFO(1, "Found sym node: " << foundp->nodep());
                        nodep->v3error("Expecting a data type: " << nodep->prettyNameQ());
                    } else {
                        nodep->v3error("Can't find typedef/interface: " << nodep->prettyNameQ());
                    }
                }
            }
        }
        if (forcedIfaceDotScope && m_ds.m_dotPos == DP_SCOPE && !m_ds.m_dotp) {
            UINFO(9, indent() << "iface capture reset dot state after captured typedef name="
                              << nodep->name());
            m_ds.init(m_curSymp);
        }
        if (ifaceCaptured && resolvedCapturedTypedef) { retireCapture("resolved"); }
        iterateChildren(nodep);
    }
    void visit(AstRequireDType* nodep) override {
        // Handle type validation for localparam type assignments
        // Iterate child to resolve any ParseRef nodes
        iterateChildren(nodep);
        // Only emit error if the child is not a type.
        // Do NOT unwrap valid types here - leave that to V3Width.
        // Unwrapping here breaks type parameter resolution during cloning.
        if (nodep->lhsp() && !VN_IS(nodep->lhsp(), NodeDType)) {
            // Not a type - emit error
            if (AstConst* const constp = VN_CAST(nodep->lhsp(), Const)) {
                nodep->lhsp()->v3error(
                    "Expecting a data type, not a constant: " << constp->toSInt());
            } else {
                nodep->lhsp()->v3error("Expecting a data type, not "
                                       << nodep->lhsp()->typeName() << ": '"
                                       << nodep->lhsp()->prettyName() << "'");
            }
            // Replace with void to keep AST valid and allow clean exit
            nodep->replaceWith(new AstVoidDType{nodep->fileline()});
            VL_DO_DANGLING(pushDeletep(nodep), nodep);
        }
    }
    void visit(AstDpiExport* nodep) override {
        // AstDpiExport: Make sure the function referenced exists, then dump it
        LINKDOT_VISIT_START();
        iterateChildren(nodep);
        checkNoDot(nodep);
        VSymEnt* const foundp = m_curSymp->findIdFallback(nodep->name());
        AstNodeFTask* const taskp = foundp ? VN_AS(foundp->nodep(), NodeFTask) : nullptr;
        if (!taskp) {
            nodep->v3error(
                "Can't find definition of exported task/function: " << nodep->prettyNameQ());
        } else if (taskp->dpiExport()) {
            nodep->v3error("Function was already DPI Exported, duplicate not allowed: "
                           << nodep->prettyNameQ());
        } else {
            taskp->dpiExport(true);
            if (nodep->cname() != "") taskp->cname(nodep->cname());
        }
        VL_DO_DANGLING(pushDeletep(nodep->unlinkFrBack()), nodep);
    }
    void visit(AstDisable* nodep) override {
        LINKDOT_VISIT_START();
        checkNoDot(nodep);
        VL_RESTORER(m_ds);
        m_ds.init(m_curSymp);
        m_ds.m_dotPos = DP_FIRST;
        m_ds.m_disablep = nodep;
        iterateChildren(nodep);
        if (nodep->targetRefp()) {
            if (AstTaskRef* const taskRefp = VN_CAST(nodep->targetRefp(), TaskRef)) {
                nodep->targetp(taskRefp->taskp());
            } else if (!VN_IS(nodep->targetRefp(), ParseRef)) {
                // If it is a ParseRef, either it couldn't be linked or it is linked to a block
                nodep->v3warn(E_UNSUPPORTED, "Node of type "
                                                 << nodep->targetRefp()->prettyTypeName()
                                                 << " referenced by disable");
                pushDeletep(nodep->unlinkFrBack());
            }
            if (nodep->targetp()) {
                // If the target is already linked, there is no need to store reference as child
                VL_DO_DANGLING(nodep->targetRefp()->unlinkFrBack()->deleteTree(), nodep);
            }
        }
    }
    void visit(AstPackageImport* nodep) override {
        // No longer needed
        LINKDOT_VISIT_START();
        checkNoDot(nodep);
        if (m_statep->forParamed()) VL_DO_DANGLING(pushDeletep(nodep->unlinkFrBack()), nodep);
    }
    void visit(AstPackageExport* nodep) override {
        // No longer needed
        LINKDOT_VISIT_START();
        checkNoDot(nodep);
        if (m_statep->forParamed()) VL_DO_DANGLING(pushDeletep(nodep->unlinkFrBack()), nodep);
    }
    void visit(AstPackageExportStarStar* nodep) override {
        // No longer needed
        LINKDOT_VISIT_START();
        checkNoDot(nodep);
        if (m_statep->forParamed()) VL_DO_DANGLING(pushDeletep(nodep->unlinkFrBack()), nodep);
    }
    void visit(AstCellRef* nodep) override {
        LINKDOT_VISIT_START();
        UINFO(5, indent() << "visit " << nodep);
        iterateChildren(nodep);
    }
    void visit(AstCellArrayRef* nodep) override {
        LINKDOT_VISIT_START();
        UINFO(5, indent() << "visit " << nodep);
        // Expression already iterated
    }
    void visit(AstUnlinkedRef* nodep) override {
        LINKDOT_VISIT_START();
        UINFO(5, indent() << "visit " << nodep);
        // No need to iterate, if we have a UnlinkedVarXRef, we're already done
    }
    void visit(AstStmtExpr* nodep) override {
        LINKDOT_VISIT_START();
        checkNoDot(nodep);
        // Check if nodep represents a super.new call;
        if (AstNew* const newExprp = VN_CAST(nodep->exprp(), New)) {
            // in this case it was already linked, so it doesn't have a super reference
            m_explicitSuperNewp = newExprp;
        } else if (const AstDot* const dotp = VN_CAST(nodep->exprp(), Dot)) {
            if (dotp->lhsp()->name() == "super") {
                if (AstNew* const newExprp = VN_CAST(dotp->rhsp(), New)) {
                    m_explicitSuperNewp = newExprp;
                }
            }
        }
        iterateChildren(nodep);
    }

    void visit(AstIfaceRefDType* nodep) override {
        if (nodep->user3SetOnce()) return;
        LINKDOT_VISIT_START();
        if (nodep->paramsp()) {
            // If there is no parameters, there is no need to visit this node.
            AstIface* const ifacep = nodep->ifacep();
            UASSERT_OBJ(ifacep, nodep, "Port parameters of AstIfaceRefDType without ifacep()");
            if (ifacep->dead()) return;
            checkNoDot(nodep);
            VL_RESTORER(m_usedPins);
            m_usedPins.clear();
            VL_RESTORER(m_pinSymp);
            m_pinSymp = m_statep->getNodeSym(ifacep);
            iterateAndNextNull(nodep->paramsp());
        }
    }

    void visit(AstAttrOf* nodep) override { iterateChildren(nodep); }

    void visit(AstAssignW* nodep) override {
        LINKDOT_VISIT_START();
        checkNoDot(nodep);
        VL_RESTORER(m_replaceWithAlias);
        if (nodep->user2()) m_replaceWithAlias = false;
        iterateChildren(nodep);
    }

    void visit(AstNode* nodep) override {
        VL_RESTORER(m_inPackedArray);
        if (VN_IS(nodep, PackArrayDType)) {
            m_inPackedArray = true;
        } else if (!m_inPackedArray) {
            LINKDOT_VISIT_START();
            checkNoDot(nodep);
        }
        iterateChildren(nodep);
    }

public:
    // CONSTRUCTORS
    LinkDotResolveVisitor(AstNetlist* rootp, LinkDotState* statep)
        : m_statep{statep} {
        UINFO(4, __FUNCTION__ << ": ");

        if (m_statep->forParamed()) {
            V3LinkDotIfaceCapture::forEach(
                [](const V3LinkDotIfaceCapture::CapturedIfaceTypedef& entry) {
                    if (AstRefDType* const refp = entry.refp) refp->user3(false);
                });
        }

        iterate(rootp);
        std::map<std::string, AstNodeModule*> modulesToRevisit = std::move(m_modulesToRevisit);
        m_lastDeferredp = nullptr;
        for (auto& p : modulesToRevisit) {
            AstNodeModule* const modp = p.second;
            modp->foreach([](AstNode* const nodep) { nodep->user3(false); });
            iterate(modp);
        }
    }
    ~LinkDotResolveVisitor() override = default;
};

